1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const COMPONENT_PREMIUM = 25;
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	
27	const FIRST_INSURANCE_SURCHARGE = 1.1;
28	const PROCESSING_FEE = 5;
29	
30	// Base premium for `count` alike components: a group of exactly 3 forms a
31	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
32	// COMPONENT_PREMIUM.
33	const componentGroupPremium = (count: number): number =>
34	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
35	
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
37	
38	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
39	
40	// Count how many alike components of each type appear (e.g. { rune: 2 }).
41	const countByType = (items: Item[]): Map<string, number> =>
42	  items.reduce((counts, item) => {
43	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
44	    return counts;
45	  }, new Map<string, number>());
46	
47	const mainItemsPremium = (items: Item[]): number =>
48	  sum(items.filter((item) => !isComponent(item)).map((item) => BASE_PREMIUM[item.type] ?? 0));
49	
50	const componentsPremium = (items: Item[]): number =>
51	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
52	
53	const basePremium = (items: Item[]): number =>
54	  mainItemsPremium(items) + componentsPremium(items);
55	
56	// Round up to a whole number in MHPCO's favour, guarding against
57	// floating-point noise (e.g. 197.5000000001) before the ceiling.
58	const roundUpToWhole = (value: number): number => Math.ceil(Math.round(value * 1e6) / 1e6);
59	
60	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
61	  const results = scenario.steps.map((step) => {
62	    const base = basePremium(step.items);
63	    const premium = base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
64	    return { premium: roundUpToWhole(premium) };
65	  });
66	  return { results };
67	};
